properties.valueHandler:
const selectedComponent = Utils.first($selectedComponents);
let currentSize = '';
let isDisabled = false;
if (selectedComponent?.input?.size?.type == 'handler' && selectedComponent?.input?.size?.value) {
  isDisabled = true;
} else {
  currentSize = selectedComponent?.input?.size?.value || 'default';
}
const options = [
  { value: 'small', label: 'S', disabled: isDisabled },
  { value: 'default', label: 'M', disabled: isDisabled }
];
const radioType = 'button';
return [options, currentSize, radioType];

eventHandlers.changed:
const selectedComponent = Utils.first($selectedComponents);
if (selectedComponent) {
  updateInput(selectedComponent, 'size', 'string', EventData.value);
}

