const selectedComponent = Utils.first($selectedComponents);
let currentValue = true;
let isDisabled = false;
if (selectedComponent?.input?.bordered?.type == 'handler' && selectedComponent?.input?.bordered?.value) {
  isDisabled = true;
} else {
  currentValue = selectedComponent?.input?.bordered?.value !== false;
}
const options = [
  { value: false, icon: 'toggle-off', disabled: isDisabled },
  { value: true, icon: 'toggle-on', disabled: isDisabled }
];
const radioType = 'button';
return [options, currentValue, radioType];

eventHandlers.changed:
const selectedComponent = Utils.first($selectedComponents);
if (selectedComponent) {
  updateInput(selectedComponent, 'bordered', 'boolean', EventData.value);
}
